create table dirkspzm32.s_erp_rcv_auftr (
    firma_nr             number(2, 0) not null enable,
    auf_id               number(*, 0) not null enable,
    vorgang              number(*, 5),
    satzart              varchar2(2 char) not null enable,
    auftrag              number(10, 0),
    pos_nr               number(10, 0),
    upos_nr              number(10, 0),
    best_term            date,
    artikel              varchar2(30 char),
    adr_art              varchar2(1 char),
    adr_nr               varchar2(20 char),
    adr_liefer           varchar2(20 char),
    leitzahl             number(*, 5),
    charge               varchar2(60 char),
    seriennr             varchar2(20 char),
    strategie            varchar2(10 char),
    mhd                  date,
    li_nr                number(10, 0),
    li_pos_nr            number(10, 0),
    arbeitsplatz_id      varchar2(10 char),
    kom_info             varchar2(40 char),
    soll_mg              number(12, 3),
    ist_menge            number(12, 3),
    status               varchar2(2 char) not null enable,
    wa_ziel              varchar2(6 char),
    lvs_info             varchar2(40 char),
    prioritaet           number(1, 0),
    best_nr_kunde        varchar2(30 char),
    lam_sel1             varchar2(30 char),
    lam_sel2             varchar2(30 char),
    lam_sel3             varchar2(30 char),
    lam_sel4             varchar2(30 char),
    lam_sel5             varchar2(30 char),
    lam_sel6             varchar2(30 char),
    lam_sel7             varchar2(30 char),
    lam_sel8             varchar2(30 char),
    lam_sel9             varchar2(30 char),
    lam_sel10            varchar2(30 char),
    tour                 varchar2(20 char),
    kom_lgr_orte         varchar2(200 char),
    prod_params          varchar2(4000 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.s_erp_rcv_auftr
    add constraint ix_s_erp_res_auf_ins
        unique ( firma_nr,
                 satzart,
                 vorgang,
                 auftrag,
                 pos_nr,
                 upos_nr,
                 li_nr,
                 li_pos_nr )
            using index enable;

alter table dirkspzm32.s_erp_rcv_auftr
    add constraint pk_s_erp_res_auftraege primary key ( firma_nr,
                                                        auf_id )
        using index enable;


